const lead = $input.item.json;
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const validEmail = emailRe.test(lead.email || '');
const validSize = (lead.company_size || 0) >= 10;
const spamHints = ['click here', 'claim your prize', 'winner@'];
const combined = `${lead.email} ${lead.message || ''}`.toLowerCase();
const isSpam = spamHints.some((h) => combined.includes(h));
let status = 'validated';
let review_reason = null;
let requires_human_review = false;
if (!validEmail || !validSize || isSpam) {
  status = 'rejected';
  review_reason = isSpam ? 'Spam indicators detected' : 'Invalid email or company size below 10';
}
const crypto = require('crypto');
const input_hash = crypto.createHash('sha256').update(`${lead.email}|${lead.name}|${lead.message || ''}`).digest('hex');
return [{ json: { ...lead, status, review_reason, requires_human_review, input_hash } }];
